class Solution:
    def maxUncrossedLines(self, nums1, nums2):
        from functools import lru_cache
        n, m = len(nums1), len(nums2)
        import sys
        sys.setrecursionlimit(10000)
        @lru_cache(maxsize=None)
        def f(i, j):
            if i == n or j == m:
                return 0
            if nums1[i] == nums2[j]:
                return 1 + f(i + 1, j + 1)
            return max(f(i + 1, j), f(i, j + 1))
        return f(0, 0)

